  ],
  "questionProse": [
    "हैश टेबल में किसी एलिमेंट को एक्सेस करने की औसत समय जटिलता क्या है?"
  ],
  "explanationProse": [
    "एक अच्छे हैश फंक्शन के तहत, जो कोलिज़न को कम करता है, हैश टेबल में एलिमेंट्स को एक्सेस करने की औसत समय जटिलता O(1) होती है। ऐसा इसलिए होता है क्योंकि हैश फंक्शन सीधे डेटा के मेमोरी एड्रेस को मैप करता है, जिससे हमें पूरे डेटा सेट को इटरेट करने की ज़रूरत नहीं पड़ती।"
  ]
}
